import { takeLatest, put, call, all } from 'redux-saga/effects';
import { signInWithPopup } from 'firebase/auth';
import { auth, googleProvider, createUserProfileDocument } from '../../firebase/firebase.utils';

import userActionTypes from "../user/user.types";
import  { googleSignInSuccess } from "../user/user.actions";
import { getDoc } from '@firebase/firestore';

export function* googleSignInAsync () {
    try {
        const userAuth = yield signInWithPopup(auth, googleProvider);
        yield console.log(userAuth);
        const userRef = yield createUserProfileDocument(userAuth);
        const user = yield getDoc(userRef);
        put(googleSignInSuccess({id: user.id, ...user.data()}))

    } catch(error) {
    }  
}

export function* googleSignInStart () {
    yield takeLatest(userActionTypes.GOOGLE_SIGNIN_START, googleSignInAsync);
}

export function* userSagas () {
    yield all([
        call(googleSignInStart)
    ])
}
